import{_ as s,o as i,c as o,a3 as t}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Jeu Concours","description":"Animez votre communauté et monétisez votre audience grâce à des opérations financées par les marques. Guide complet de mise en place et conformité RGPD.","frontmatter":{"title":"Jeu Concours","description":"Animez votre communauté et monétisez votre audience grâce à des opérations financées par les marques. Guide complet de mise en place et conformité RGPD.","keywords":["jeu concours","co-brandé","leads","opt-in","rgpd","monétisation audience"]},"headers":[],"relativePath":"publishers/co-branded-contest/index.md","filePath":"publishers/co-branded-contest/index.md"}'),a={name:"publishers/co-branded-contest/index.md"};function r(n,e,c,l,d,u){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="jeu-concours" tabindex="-1">Jeu Concours <a class="header-anchor" href="#jeu-concours" aria-label="Permalink to &quot;Jeu Concours&quot;">​</a></h1><p>Animez votre communauté tout en monétisant votre audience grâce à des opérations financées par les marques.</p><hr><h2 id="pourquoi-proposer-ce-format" tabindex="-1">Pourquoi proposer ce format ? <a class="header-anchor" href="#pourquoi-proposer-ce-format" aria-label="Permalink to &quot;Pourquoi proposer ce format ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💰 Revenus Média</strong><p>L&#39;annonceur finance tout — dotations, lots, coûts opérationnels. Source de revenus 100% additionnel, sans risque pour vous.</p></div><div class="gi-value-card"><strong>🎉 Animation Commerciale</strong><p>Offrez une expérience ludique et des cadeaux attractifs à vos clients. Cela dynamise votre site et vos newsletters.</p></div><div class="gi-value-card"><strong>📊 Qualification Data</strong><p>Réactivez des clients inactifs et collectez des leads opt-in ultra-qualifiés — qualifiés par le comportement d&#39;achat de votre propre audience.</p></div></div><hr><h2 id="le-concept" tabindex="-1">Le Concept <a class="header-anchor" href="#le-concept" aria-label="Permalink to &quot;Le Concept&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Vous hébergez une <strong>page de jeu sur votre site</strong> (ou une page dédiée externe). Vous dirigez du trafic dessus via vos canaux habituels (Email, Push, Social). L&#39;Annonceur récupère les leads &quot;Opt-in&quot; à la fin de l&#39;opération.</p></div><hr><h2 id="pourquoi-passer-par-getinside" tabindex="-1">Pourquoi passer par getinside ? <a class="header-anchor" href="#pourquoi-passer-par-getinside" aria-label="Permalink to &quot;Pourquoi passer par getinside ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚖️ Sécurité Juridique</strong><p>La collecte de data partagée est complexe (RGPD). Nous fournissons les modèles de mentions légales et de cases à cocher validés par des juristes.</p></div><div class="gi-value-card"><strong>🤝 Gestion des Dotations</strong><p>Vous ne gérez pas l&#39;envoi des lots aux gagnants — c&#39;est l&#39;Annonceur qui s&#39;en charge. Votre responsabilité s&#39;arrête à l&#39;hébergement du jeu.</p></div></div><hr><h2 id="guide-de-mise-en-place" tabindex="-1">Guide de mise en place <a class="header-anchor" href="#guide-de-mise-en-place" aria-label="Permalink to &quot;Guide de mise en place&quot;">​</a></h2><p>Les étapes techniques et juridiques pour lancer un jeu concours conforme.</p><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Création de la Landing Page (LP)</h3><p>Vous êtes responsable de l&#39;hébergement du jeu pour rassurer votre client.</p><ul><li><strong>URL :</strong> Sur votre domaine (ex: <code>votre-site.com/jeu-concours-marque</code>).</li><li><strong>Design :</strong> Co-brandé (Votre header habituel + l&#39;univers visuel de l&#39;Annonceur).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Le Formulaire &amp; RGPD (Critique)</h3><p>Pour monétiser la donnée (vendre le lead à l&#39;annonceur), le formulaire doit respecter strictement le RGPD.</p><div class="danger custom-block"><p class="custom-block-title">Mention obligatoire — case non pré-cochée</p><p>☐ <em>J&#39;accepte de recevoir les offres commerciales du partenaire [Nom de l&#39;Annonceur].</em></p><p>⚠️ Cette case ne doit <strong>JAMAIS</strong> être pré-cochée.</p></div><pre><code>&lt;p&gt;&lt;em&gt;Note : Seuls les participants cochant cette case seront facturés à l&#39;Annonceur. Les autres jouent mais ne sont pas monétisables.&lt;/em&gt;&lt;/p&gt;
</code></pre></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Plan d&#39;activation</h3><p>Pour garantir le volume de leads (et donc vos revenus), activez vos leviers puissants :</p><ul><li><strong>📧 Newsletter dédiée :</strong> &quot;Tentez de gagner XXX€ chez [Marque]&quot;.</li><li><strong>🔔 Web Push Notification.</strong></li><li><strong>🖼️ Bannières Home Page.</strong></li></ul></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Transfert des données</h3><p>À la clôture du jeu :</p><ol><li>Exportez la liste des participants <strong>avec l&#39;opt-in partenaire</strong> (CSV/Excel).</li><li>Transmettez le fichier de manière sécurisée à l&#39;Annonceur (via getinside).</li></ol><div class="tip custom-block"><p class="custom-block-title">Votre travail s&#39;arrête ici</p><p>Une fois le fichier transmis, l&#39;annonceur intègre les leads dans son CRM et envoie <strong>immédiatement</strong> l&#39;email de bienvenue avec le code promo de consolation promis. La rapidité est clé pour maximiser les ventes.</p></div></div></div>`,18)])])}const v=s(a,[["render",r]]);export{m as __pageData,v as default};
